/// <summary>
/// The <c>ETG_EstimationVsActualContract</c> class is the data contract class for sales register report
/// report.
/// </summary>
[
    DataContractAttribute
    //SysOperationContractProcessingAttribute(classstr(ETG_EstimationVsActualUIBuilder))
    //SysOperationGroupAttribute('DateRange', "@SYS41297", '1')
    ]
    public class ETG_EstimationVsActualContract implements SysOperationValidatable
{
    FromDate                fromDate;
    ToDate                  toDate;
    ETG_Agreement           etg_agreement;
    ETG_AccrualType         etg_AccrualType;

}

Method.Source:
[
    DataMemberAttribute('Agreement'),
    SysOperationLabelAttribute(literalStr("Agreement")),
    SysOperationDisplayOrderAttribute('1')
    //SysOperationGroupMemberAttribute('DateRange')
]
public ETG_Agreement parmAgreement(ETG_Agreement _etg_agreement = etg_agreement)
{
    etg_agreement = _etg_agreement;
    return etg_agreement;
}

[
    DataMemberAttribute('AccrualType'),
    SysOperationLabelAttribute(literalStr("Accrual Type")),
    SysOperationDisplayOrderAttribute('2')
    //SysOperationGroupMemberAttribute('DateRange')
]
public ETG_AccrualType parmAccrualType(ETG_AccrualType _etg_AccrualType = etg_AccrualType)
{
    etg_AccrualType = _etg_AccrualType;
    return etg_AccrualType;
}

[
    DataMemberAttribute('FromDate'),
    SysOperationLabelAttribute(literalStr("@SYS5209")),
    SysOperationHelpTextAttribute(literalStr("@SYS5209")),
    SysOperationDisplayOrderAttribute('3')
    //SysOperationGroupMemberAttribute('DateRange')
]
public FromDate parmFromDate(FromDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

[
    DataMemberAttribute('ToDate'),
    SysOperationLabelAttribute(literalStr("@SYS14656")),
    SysOperationHelpTextAttribute(literalStr("@SYS14656")),
    SysOperationDisplayOrderAttribute('4')
    //SysOperationGroupMemberAttribute('DateRange')
]
public ToDate parmToDate(ToDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}

public boolean validate()
{
    boolean isValid = true;
    if (!fromDate)
    {
        isValid = checkFailed(strFmt("@SYS84753", "@SYS180311"));
    }
    if (!toDate)
    {
        isValid = checkFailed(strFmt("@SYS84753", "@SYS180217"));
    }
    if (fromDate > toDate)
    {
        isValid = checkFailed("@SYS300457");
    }
    return isValid;
}
